import os

def get_available_features() -> list[str]:
    """
    Get the list of available API features exposed via /version endpoint.
    "diagnostics" is controlled by AGENTDEV_DIAGNOSTICS_API environment variable.
    """
    features: list[str] = []
    if os.environ.get("AGENTDEV_DIAGNOSTICS_API", "").lower() in ("true", "1"):
        features.append("diagnostics")
    return features
